from django import forms

from .registry import SimulationSpec


_LATEX_HELP_SUFFIX = "Escriba LaTeX sin $...$; la vista previa se actualiza al escribir."


class DynamicSimulationForm(forms.Form):
    @staticmethod
    def _build_parameter_field(parameter, common_kwargs: dict) -> forms.Field:
        if parameter.kind == "int":
            return forms.IntegerField(
                min_value=parameter.min_value,
                max_value=parameter.max_value,
                **common_kwargs,
            )
        if parameter.kind == "float":
            return forms.FloatField(
                min_value=parameter.min_value,
                max_value=parameter.max_value,
                **common_kwargs,
            )
        raise ValueError(f"Tipo de parametro no soportado: {parameter.kind}")

    def __init__(self, spec: SimulationSpec, *args, **kwargs):
        self.spec = spec
        super().__init__(*args, **kwargs)

        for expression in spec.expressions:
            self.fields[expression.name] = forms.CharField(
                label=expression.label,
                initial=expression.default,
                help_text=(f"{expression.help_text} {_LATEX_HELP_SUFFIX}").strip(),
                widget=forms.TextInput(
                    attrs={
                        "placeholder": expression.default,
                        "data-math-input": "true",
                    }
                ),
            )

        for parameter in spec.parameters:
            common_kwargs = {
                "label": parameter.label,
                "initial": parameter.default,
                "help_text": parameter.help_text,
            }
            self.fields[parameter.name] = self._build_parameter_field(parameter, common_kwargs)

        if "precision" not in self.fields:
            self.fields["precision"] = forms.IntegerField(
                label="Precision (decimales)",
                initial=6,
                min_value=0,
                max_value=12,
                help_text="Cantidad de decimales usada en los calculos y resultados.",
            )

from django import forms

from .registry import SimulationSpec


_LATEX_HELP_SUFFIX = "Escriba LaTeX sin $...$; la vista previa se actualiza al escribir."


class DynamicSimulationForm(forms.Form):
    @staticmethod
    def _build_parameter_field(parameter, common_kwargs: dict) -> forms.Field:
        if parameter.kind == "int":
            return forms.IntegerField(
                min_value=parameter.min_value,
                max_value=parameter.max_value,
                **common_kwargs,
            )
        if parameter.kind == "float":
            return forms.FloatField(
                min_value=parameter.min_value,
                max_value=parameter.max_value,
                **common_kwargs,
            )
        raise ValueError(f"Tipo de parametro no soportado: {parameter.kind}")

    def __init__(self, spec: SimulationSpec, *args, **kwargs):
        self.spec = spec
        super().__init__(*args, **kwargs)

        for expression in spec.expressions:
            self.fields[expression.name] = forms.CharField(
                label=expression.label,
                initial=expression.default,
                help_text=(f"{expression.help_text} {_LATEX_HELP_SUFFIX}").strip(),
                widget=forms.TextInput(
                    attrs={
                        "placeholder": expression.default,
                        "data-math-input": "true",
                    }
                ),
            )

        for parameter in spec.parameters:
            common_kwargs = {
                "label": parameter.label,
                "initial": parameter.default,
                "help_text": parameter.help_text,
            }
            if parameter.name == "xi":
                common_kwargs["required"] = False
            self.fields[parameter.name] = self._build_parameter_field(parameter, common_kwargs)

        if "precision" not in self.fields:
            self.fields["precision"] = forms.IntegerField(
                label="Precision (decimales)",
                initial=6,
                min_value=0,
                max_value=12,
                help_text="Cantidad de decimales usada en los calculos y resultados.",
            )

:root {
    --bg: #0b1220;
    --surface: #111a2e;
    --surface-soft: #17233d;
    --border: #2a3b5f;
    --text: #e5e7eb;
    --muted: #9ca3af;
    --link: #7dd3fc;
    --accent: #3b82f6;
    --accent-hover: #2563eb;
    --success-bg: #102a1f;
    --success-border: #1f7a4f;
    --error: #fca5a5;
}

body {
    margin: 0;
    font-family: Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
}

.container {
    width: min(1000px, 92vw);
    margin: 0 auto;
    padding: 1rem 0;
}

nav {
    display: flex;
    gap: 1rem;
    margin-bottom: 1rem;
}

a {
    color: var(--link);
}

.button {
    display: inline-block;
    background: var(--accent);
    color: #fff;
    text-decoration: none;
    border: 0;
    padding: 0.5rem 0.8rem;
    border-radius: 0.4rem;
    cursor: pointer;
}

.button:hover {
    background: var(--accent-hover);
}

.cards {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
    gap: 1rem;
}

.card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 0.6rem;
    padding: 1rem;
}

.form-grid {
    display: grid;
    gap: 1rem;
    max-width: 500px;
}

.math-preview-wrap {
    margin-top: 0.4rem;
    padding: 0.75rem;
    border: 1px solid var(--border);
    border-radius: 0.45rem;
    background: var(--surface-soft);
}

.math-preview-label {
    font-size: 0.85rem;
    color: var(--muted);
    margin-bottom: 0.35rem;
}

.math-preview {
    min-height: 1.8rem;
    font-size: 1.05rem;
    line-height: 1.7;
    overflow-x: auto;
}

.math-empty {
    color: var(--muted);
    font-style: italic;
}


input {
    width: 100%;
    box-sizing: border-box;
    padding: 0.45rem;
    border: 1px solid var(--border);
    background: var(--surface);
    color: var(--text);
    border-radius: 0.3rem;
}

input:focus {
    outline: 2px solid var(--accent);
    outline-offset: 1px;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 1rem;
    background: var(--surface);
}

th,
td {
    border: 1px solid var(--border);
    padding: 0.4rem;
    text-align: left;
}

th {
    background: var(--surface-soft);
}

.chart {
    width: 100%;
    border: 1px solid var(--border);
    border-radius: 0.4rem;
    margin-bottom: 1rem;
    background: var(--surface);
}

.chart-panzoom-frame {
    overflow: hidden;
    border: 1px solid var(--border);
    border-radius: 0.4rem;
    margin-bottom: 1rem;
    background: var(--surface);
}

.chart-panzoom-frame > .chart {
    border: 0;
    border-radius: 0;
    margin-bottom: 0;
    display: block;
    transform-origin: 0 0;
    will-change: transform;
    cursor: grab;
    user-select: none;
    touch-action: none;
}

.chart-panzoom-frame > .chart.is-dragging {
    cursor: grabbing;
}

.messages {
    list-style: none;
    padding: 0;
}

.message {
    background: var(--success-bg);
    border: 1px solid var(--success-border);
    padding: 0.6rem;
    border-radius: 0.4rem;
    margin-bottom: 0.8rem;
}

.errorlist,
.error-list {
    color: var(--error);
    margin: 0.2rem 0;
}

