{% load static %}
<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>{% block title %}Modelado y Simulacion{% endblock %}</title>
    <link rel="stylesheet" href="{% static 'css/site.css' %}">
</head>
<body>
<header class="container">
    <h1>Modelado y Simulacion</h1>
    <nav>
        <a href="{% url 'core:home' %}">Inicio</a>
        <a href="{% url 'simulations:list' %}">Simulaciones</a>
        <a href="{% url 'core:about' %}">Acerca de</a>
    </nav>
</header>
<main class="container">
    {% if messages %}
        <ul class="messages">
            {% for message in messages %}
                <li class="message {{ message.tags }}">{{ message }}</li>
            {% endfor %}
        </ul>
    {% endif %}

    {% block content %}{% endblock %}
</main>
<script>
window.MathJax = {
    tex: {
        inlineMath: [['\\(', '\\)']],
        displayMath: [['\\[', '\\]']]
    },
    svg: {
        fontCache: 'local'
    },
    startup: {
        ready: function () {
            MathJax.startup.defaultReady();
            if (window.__resolveMathJaxReady) {
                window.__resolveMathJaxReady();
            }
        }
    }
};
window.__mathjaxReadyPromise = new Promise(function (resolve) {
    window.__resolveMathJaxReady = resolve;
});
</script>
<script defer src="{% static 'vendor/mathjax/tex-svg.js' %}"></script>
{% block extra_scripts %}{% endblock %}
</body>
</html>

